import{_ as p,c as r}from"./app.0b00aae6.js";const t={},n=r('<h1 id="_08-\u8BB2-\u4EE5\u7EC8\u4E3A\u59CB-\u5982\u4F55\u624D\u80FD\u505A\u597D\u6D4B\u8BD5\u8BA1\u5212" tabindex="-1"><a class="header-anchor" href="#_08-\u8BB2-\u4EE5\u7EC8\u4E3A\u59CB-\u5982\u4F55\u624D\u80FD\u505A\u597D\u6D4B\u8BD5\u8BA1\u5212" aria-hidden="true">#</a> 08 \u8BB2\uFF1A\u4EE5\u7EC8\u4E3A\u59CB\uFF0C\u5982\u4F55\u624D\u80FD\u505A\u597D\u6D4B\u8BD5\u8BA1\u5212\uFF1F</h1><p>\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4E3A\u4F60\u4ECB\u7ECD\u4E86\u5982\u4F55\u9AD8\u6548\u586B\u5199\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A\uFF0C\u5E76\u4E3A\u4F60\u89E3\u8BFB\u4E86\u7F3A\u9677\u62A5\u544A\u4E2D\u7684\u5173\u952E\u5185\u5BB9\u3002\u4ECA\u5929\uFF0C\u6211\u5C06\u4E3A\u4F60\u4ECB\u7ECD\u4E00\u4EFD\u6210\u529F\u7684\u6D4B\u8BD5\u8BA1\u5212\u5E94\u8BE5\u5305\u542B\u54EA\u4E9B\u5185\u5BB9\uFF0C\u4EE5\u53CA\u5982\u4F55\u624D\u80FD\u505A\u597D\u6D4B\u8BD5\u8BA1\u5212\u3002</p><p>\u8F6F\u4EF6\u9879\u76EE\uFF0C\u901A\u5E38\u90FD\u4F1A\u6709\u8BE6\u7EC6\u7684\u9879\u76EE\u8BA1\u5212\u3002\u8F6F\u4EF6\u6D4B\u8BD5\u4F5C\u4E3A\u6574\u4E2A\u9879\u76EE\u4E2D\u7684\u91CD\u8981\u4E00\u73AF\uFF0C\u4E5F\u8981\u6267\u884C\u8BE6\u7EC6\u7684\u6D4B\u8BD5\u8BA1\u5212\u3002\u6B63\u6240\u8C13\u8FD0\u7B79\u5E37\u5E44\u4E4B\u4E2D\uFF0C\u51B3\u80DC\u5343\u91CC\u4E4B\u5916\uFF0C\u5F3A\u8C03\u7684\u5C31\u662F\u9884\u5148\u8BA1\u5212\u7684\u91CD\u8981\u6027\u548C\u5FC5\u8981\u6027\u3002</p><p>\u5728\u65E9\u671F\u7684\u8F6F\u4EF6\u5DE5\u7A0B\u5B9E\u8DF5\u4E2D\uFF0C\u8F6F\u4EF6\u6D4B\u8BD5\u8BA1\u5212\u7684\u5236\u5B9A\u901A\u5E38\u662F\u5728\u9700\u6C42\u5206\u6790\u4EE5\u53CA\u6D4B\u8BD5\u9700\u6C42\u5206\u6790\u5B8C\u6210\u540E\u5F00\u59CB\uFF0C\u5E76\u4E14\u662F\u6574\u4E2A\u8F6F\u4EF6\u7814\u53D1\u751F\u547D\u5468\u671F\u4E2D\u7684\u91CD\u8981\u73AF\u8282\u3002</p><p>\u4F46\u662F\uFF0C\u5728\u654F\u6377\u5F00\u53D1\u6A21\u5F0F\u4E0B\uFF0C\u4F60\u53EF\u80FD\u4F1A\u6709\u8FD9\u6837\u7684\u7591\u95EE\uFF0C\u8F6F\u4EF6\u6D4B\u8BD5\u8BA1\u5212\u8FD8\u6709\u90A3\u4E48\u91CD\u8981\u5417\uFF1F\u6211\u6240\u5728\u7684\u8F6F\u4EF6\u9879\u76EE\u538B\u6839\u513F\u5C31\u6CA1\u6709\u6B63\u5F0F\u7684\u6D4B\u8BD5\u8BA1\u5212\uFF0C\u4E0D\u4E5F\u6CA1\u51FA\u4EC0\u4E48\u5927\u95EE\u9898\u5417\uFF1F</p><p>\u7684\u786E\uFF0C\u5BF9\u4E8E\u5F88\u591A\u975E\u4EA7\u54C1\u578B\u7684\u4E92\u8054\u7F51\u516C\u53F8\uFF0C\u7531\u4E8E\u91C7\u7528\u4E86\u654F\u6377\u5F00\u53D1\u6A21\u5F0F\uFF0C\u7684\u786E\u5F88\u5C11\u53BB\u5236\u5B9A\u4F20\u7EDF\u610F\u4E49\u4E0A\u7684\u6D4B\u8BD5\u8BA1\u5212\u4E86\uFF0C\u4F46\u8FD9\u5E76\u4E0D\u662F\u8BF4\u5B83\u4EEC\u5C31\u4E0D\u518D\u5236\u5B9A\u6D4B\u8BD5\u8BA1\u5212\u4E86\u3002</p><p>\u53EA\u4E0D\u8FC7\u662F\uFF0C\u6D4B\u8BD5\u8BA1\u5212\u7684\u8868\u73B0\u5F62\u5F0F\u5DF2\u7ECF\u4E0D\u518D\u662F\u4F20\u7EDF\u610F\u4E49\u4E0A\u5E9E\u5927\u7684\u3001\u6B63\u5F0F\u7684\u6D4B\u8BD5\u8BA1\u5212\u6587\u6863\u4E86\uFF0C\u800C\u66F4\u591A\u7684\u662F\u4F53\u73B0\u5728\u6BCF\u4E2A\u8FED\u4EE3\uFF08sprint\uFF09\u7684\u8BA1\u5212\u73AF\u8282\uFF0C\u800C\u4E14\u8FD9\u6837\u7684\u77ED\u671F\u6D4B\u8BD5\u8BA1\u5212\u53EF\u4EE5\u975E\u5E38\u8FC5\u901F\u5730\u6839\u636E\u9879\u76EE\u60C5\u51B5\u5B9E\u65F6\u8C03\u6574\u3002</p><p>\u6240\u4EE5\u8BF4\uFF0C<strong>\u6D4B\u8BD5\u8BA1\u5212\u4F9D\u65E7\u5B58\u5728\uFF0C\u53EA\u662F\u4ECE\u539F\u6765\u7684\u4E00\u6B21\u6027\u96C6\u4E2D\u5236\u5B9A\u6D4B\u8BD5\u8BA1\u5212\uFF0C\u53D8\u6210\u4E86\u4EE5\u8FED\u4EE3\u7684\u65B9\u5F0F\u6301\u7EED\u5236\u5B9A\u6D4B\u8BD5\u8BA1\u5212</strong>\u3002 \u4F46\u662F\u5BF9\u4E8E\u4F20\u7EDF\u8F6F\u4EF6\u4F01\u4E1A\uFF0C\u6216\u8005\u662F\u505A\u975E\u4E92\u8054\u7F51\u8F6F\u4EF6\u4EA7\u54C1\u7684\u4F01\u4E1A\uFF0C\u5B83\u4EEC\u901A\u5E38\u8FD8\u662F\u4F1A\u6709\u975E\u5E38\u6B63\u5F0F\u7684\u8F6F\u4EF6\u6D4B\u8BD5\u8BA1\u5212\u3002</p><p>\u7531\u6B64\u53EF\u89C1\uFF0C\u65E0\u8BBA\u5BF9\u4E8E\u65E9\u671F\u6700\u5177\u5178\u578B\u6027\u7684\u7011\u5E03\u5F00\u53D1\u6A21\u578B\uFF0C\u8FD8\u662F\u73B0\u5728\u7684\u654F\u6377\u5F00\u53D1\u6A21\u578B\uFF0C\u6D4B\u8BD5\u8BA1\u5212\u7684\u91CD\u8981\u6027\u59CB\u7EC8\u6CA1\u6709\u53D1\u751F\u53D8\u5316\u3002\u90A3\u4E48\uFF0C\u4F60\u53EF\u80FD\u4F1A\u95EE\uFF0C\u6D4B\u8BD5\u8BA1\u5212\u7684\u91CD\u8981\u6027\u5230\u5E95\u4F53\u73B0\u5728\u54EA\u4E9B\u65B9\u9762\u5462\uFF1F\u5728\u56DE\u7B54\u8FD9\u4E2A\u95EE\u9898\u4E4B\u524D\uFF0C\u6211\u5148\u8DDF\u4F60\u804A\u804A\u5982\u679C\u6CA1\u6709\u6D4B\u8BD5\u8BA1\u5212\u4F1A\u5E26\u6765\u4EC0\u4E48\u95EE\u9898\u3002</p><p><strong>\u6CA1\u6709\u6D4B\u8BD5\u8BA1\u5212\u4F1A\u600E\u4E48\u6837\uFF1F</strong></p><p>\u5982\u679C\u6CA1\u6709\u6D4B\u8BD5\u8BA1\u5212\uFF0C\u4F1A\u5E26\u6765\u54EA\u4E9B\u95EE\u9898\u5462\uFF1F</p><p>\u5F88\u96BE\u786E\u5207\u5730\u77E5\u9053\u5177\u4F53\u7684\u6D4B\u8BD5\u8303\u56F4\uFF0C\u4EE5\u53CA\u5E94\u8BE5\u91C7\u53D6\u7684\u5177\u4F53\u6D4B\u8BD5\u7B56\u7565\uFF1B</p><p>\u5F88\u96BE\u9884\u4F30\u5177\u4F53\u7684\u5DE5\u4F5C\u91CF\u548C\u6240\u9700\u8981\u7684\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u6570\u91CF\uFF0C\u540C\u65F6\u8FD8\u4F1A\u9020\u6210\u5404\u4E2A\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u7684\u5206\u5DE5\u4E0D\u660E\u786E\uFF0C\u5F15\u53D1\u67D0\u4E9B\u6D4B\u8BD5\u5DE5\u4F5C\u88AB\u91CD\u590D\u6267\u884C\u800C\u6709\u4E9B\u6D4B\u8BD5\u5219\u88AB\u9057\u6F0F\u7684\u95EE\u9898\uFF1B</p><p>\u6D4B\u8BD5\u7684\u6574\u4F53\u8FDB\u5EA6\u5B8C\u5168\u4E0D\u53EF\u63A7\uFF0C\u751A\u81F3\u5F88\u96BE\u786E\u5207\u77E5\u9053\u76EE\u524D\u6D4B\u8BD5\u7684\u5B8C\u6210\u60C5\u51B5\uFF0C\u5BF9\u4E8E\u6D4B\u8BD5\u5B8C\u6210\u65F6\u95F4\u5C31\u66F4\u96BE\u9884\u4F30\u51C6\u786E\u7684\u65F6\u95F4\u8282\u70B9\u4E86\uFF1B</p><p>\u6574\u4E2A\u9879\u76EE\u5BF9\u6F5C\u5728\u98CE\u9669\u7684\u62B5\u6297\u80FD\u529B\u5F88\u5F31\uFF0C\u5F88\u96BE\u5E94\u5BF9\u9700\u6C42\u7684\u53D8\u66F4\u4EE5\u53CA\u5176\u4ED6\u7A81\u53D1\u4E8B\u4EF6\u3002</p><p>\u4ECE\u8FD9\u4E9B\u95EE\u9898\u4E2D\uFF0C\u4F60\u53EF\u4EE5\u9006\u5411\u601D\u7EF4\u63A8\u5BFC\u51FA\uFF0C\u4E00\u4EFD\u597D\u7684\u6D4B\u8BD5\u8BA1\u5212\u8981\u5305\u62EC\uFF1A\u6D4B\u8BD5\u8303\u56F4\u3001\u6D4B\u8BD5\u7B56\u7565\u3001\u6D4B\u8BD5\u8D44\u6E90\u3001\u6D4B\u8BD5\u8FDB\u5EA6\u548C\u6D4B\u8BD5\u98CE\u9669\u9884\u4F30\uFF0C\u8FD9\u4E94\u5927\u65B9\u9762\uFF0C\u5E76\u4E14\u6BCF\u4E00\u90E8\u5206\u90FD\u8981\u7ED9\u51FA\u5E94\u5BF9\u53EF\u80FD\u51FA\u73B0\u95EE\u9898\u7684\u89E3\u51B3\u529E\u6CD5\u3002</p><p><strong>\u6D4B\u8BD5\u8303\u56F4</strong></p><p>\u987E\u540D\u601D\u4E49\uFF0C\u6D4B\u8BD5\u8303\u56F4\u63CF\u8FF0\u7684\u662F\u88AB\u6D4B\u5BF9\u8C61\u4EE5\u53CA\u4E3B\u8981\u7684\u6D4B\u8BD5\u5185\u5BB9\u3002</p><p>\u6BD4\u5982\uFF0C\u5BF9\u4E8E\u7528\u6237\u767B\u5F55\u6A21\u5757\uFF0C\u529F\u80FD\u6D4B\u8BD5\u65E2\u9700\u8981\u6D4B\u8BD5\u6D4F\u89C8\u5668\u7AEF\u53C8\u9700\u8981\u6D4B\u8BD5\u79FB\u52A8\u7AEF\uFF0C\u540C\u65F6\u8FD8\u8003\u8651\u767B\u5F55\u7684\u5B89\u5168\u548C\u5E76\u53D1\u6027\u80FD\u76F8\u5173\u7684\u975E\u529F\u80FD\u6027\u9700\u6C42\u7684\u6D4B\u8BD5\u7B49\u3002</p><p>\u6D4B\u8BD5\u8303\u56F4\u7684\u786E\u5B9A\u901A\u5E38\u662F\u5728\u6D4B\u8BD5\u9700\u6C42\u5206\u6790\u5B8C\u6210\u540E\u8FDB\u884C\uFF0C\u6240\u4EE5\u786E\u5B9A\u6D4B\u8BD5\u8303\u56F4\u7684\u8FC7\u7A0B\u5728\u4E00\u5B9A\u7A0B\u5EA6\u4E0A\u4E5F\u662F\u5BF9\u6D4B\u8BD5\u9700\u6C42\u5206\u6790\u7684\u8FDB\u4E00\u6B65\u68C0\u9A8C\uFF0C\u8FD9\u5C06\u6709\u52A9\u4E8E\u5728\u65E9\u671F\u9636\u6BB5\u5C31\u53D1\u73B0\u6F5C\u5728\u7684\u6D4B\u8BD5\u9057\u6F0F\u3002</p><p>\u540C\u65F6\uFF0C\u7531\u4E8E\u4E0D\u53EF\u80FD\u8FDB\u884C\u7A77\u5C3D\u6D4B\u8BD5\uFF0C\u800C\u4E14\u6D4B\u8BD5\u7684\u65F6\u95F4\u548C\u8D44\u6E90\u90FD\u662F\u6709\u9650\u7684\uFF0C\u6240\u4EE5\u5FC5\u987B\u6709\u6240\u53D6\u820D\uFF0C\u8FDB\u884C\u6709\u9488\u5BF9\u6027\u7684\u6D4B\u8BD5\u3002<strong>\u56E0\u6B64\uFF0C\u6D4B\u8BD5\u8303\u56F4\u4E2D\u9700\u8981\u660E\u786E\u201C\u6D4B\u4EC0\u4E48\u201D\u548C\u201C\u4E0D\u6D4B\u4EC0\u4E48\u201D</strong>\u3002</p><p><strong>\u6D4B\u8BD5\u7B56\u7565\u7684\u8BDD\u9898</strong></p><p><strong>\u6D4B\u8BD5\u7B56\u7565\u7B80\u5355\u6765\u8BB2\u5C31\u662F\u9700\u8981\u660E\u786E\u201C\u5148\u6D4B\u4EC0\u4E48\u540E\u6D4B\u4EC0\u4E48\u201D\u548C\u201C\u5982\u4F55\u6765\u6D4B\u201D\u8FD9\u4E24\u4E2A\u95EE\u9898</strong>\u3002</p><p>\u75C5\u6709\u8F7B\u91CD\u7F13\u6025\uFF0C\u6D4B\u8BD5\u4E5F\u662F\u4E00\u6837\u7684\u9053\u7406\uFF0C\u91CD\u8981\u7684\u9879\u5148\u6D4B\uFF0C\u800C\u4E0D\u91CD\u8981\u7684\u9879\u8981\u540E\u6D4B\u3002\u6D4B\u8BD5\u7B56\u7565\u4F1A\u8981\u6C42\u6211\u4EEC\u660E\u786E\u6D4B\u8BD5\u7684\u91CD\u70B9\uFF0C\u4EE5\u53CA\u5404\u9879\u6D4B\u8BD5\u7684\u5148\u540E\u987A\u5E8F\u3002</p><p>\u6BD4\u5982\uFF0C\u5BF9\u7528\u6237\u767B\u5F55\u6A21\u5757\u6765\u8BB2\uFF0C\u201C\u7528\u6237\u65E0\u6CD5\u6B63\u5E38\u767B\u5F55\u201D\u548C\u201C\u7528\u6237\u65E0\u6CD5\u91CD\u7F6E\u5BC6\u7801\u201D\u8FD9\u4E24\u4E2A\u6F5C\u5728\u95EE\u9898\uFF0C\u5BF9\u4E1A\u52A1\u7684\u5F71\u54CD\u5B70\u8F7B\u5B70\u91CD\u4E00\u76EE\u4E86\u7136\uFF0C\u6240\u4EE5\uFF0C\u4F60\u5E94\u8BE5\u6309\u7167\u4F18\u5148\u7EA7\u6765\u5148\u6D4B\u201C\u7528\u6237\u6B63\u5E38\u767B\u5F55\u201D\uFF0C\u518D\u6D4B\u201C\u7528\u6237\u91CD\u7F6E\u5BC6\u7801\u201D\u3002</p><p><strong>\u6D4B\u8BD5\u7B56\u7565\u8FD8\u9700\u8981\u8BF4\u660E\uFF0C\u91C7\u7528\u4EC0\u4E48\u6837\u7684\u6D4B\u8BD5\u7C7B\u578B\u548C\u6D4B\u8BD5\u65B9\u6CD5</strong>\u3002 \u8FD9\u91CC\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u4E0D\u4EC5\u8981\u7ED9\u51FA\u4E3A\u4EC0\u4E48\u8981\u9009\u7528\u8FD9\u4E2A\u6D4B\u8BD5\u7C7B\u578B\uFF0C\u8FD8\u8981\u8BE6\u7EC6\u8BF4\u660E\u5177\u4F53\u7684\u5B9E\u65BD\u65B9\u6CD5\u3002</p><p><strong>\u7B2C\u4E00\uFF0C\u529F\u80FD\u6D4B\u8BD5</strong></p><p>\u5BF9\u4E8E\u529F\u80FD\u6D4B\u8BD5\uFF0C\u4F60\u5E94\u8BE5\u6839\u636E\u6D4B\u8BD5\u9700\u6C42\u5206\u6790\u7684\u601D\u7EF4\u5BFC\u56FE\u6765\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u4E3B\u7EBF\u4E1A\u52A1\u7684\u529F\u80FD\u6D4B\u8BD5\u7531\u4E8E\u7ECF\u5E38\u9700\u8981\u6267\u884C\u56DE\u5F52\u6D4B\u8BD5\uFF0C\u6240\u4EE5\u4F60\u9700\u8981\u8003\u8651\u5B9E\u65BD\u81EA\u52A8\u5316\u6D4B\u8BD5\uFF0C\u5E76\u4E14\u6839\u636E\u9879\u76EE\u6280\u672F\u6808\u548C\u6D4B\u8BD5\u56E2\u961F\u6210\u5458\u7684\u4E60\u60EF\u4E0E\u80FD\u529B\u6765\u9009\u62E9\u5408\u9002\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u3002</p><p><strong>\u8FD9\u91CC\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u4F60\u901A\u5E38\u5E94\u8BE5\u5148\u5B9E\u73B0\u4E3B\u5E72\u4E1A\u52A1\u6D41\u7A0B\u7684\u6D4B\u8BD5\u81EA\u52A8\u5316</strong>\u3002</p><p>\u5B9E\u9645\u64CD\u4F5C\u65F6\uFF0C\u4F60\u901A\u5E38\u9700\u8981\u5148\u5217\u51FA\u4E3B\u8981\u7684\u529F\u80FD\u6D4B\u8BD5\u70B9\uFF0C\u5E76\u51B3\u5B9A\u54EA\u4E9B\u6D4B\u8BD5\u70B9\u9002\u5408\u91C7\u7528\u81EA\u52A8\u5316\u6D4B\u8BD5\uFF0C\u5E76\u4E14\u51B3\u5B9A\u5177\u4F53\u4F7F\u7528\u4EC0\u4E48\u6837\u7684\u6846\u67B6\u548C\u6280\u672F\u3002</p><p>\u5BF9\u4E8E\u9700\u8981\u624B\u5DE5\u6D4B\u8BD5\u7684\u6D4B\u8BD5\u70B9\uFF0C\u4F60\u8981\u51B3\u5B9A\u91C7\u7528\u4EC0\u4E48\u7C7B\u578B\u7684\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u65B9\u6CD5\uFF0C\u4EE5\u53CA\u5982\u4F55\u51C6\u5907\u76F8\u5173\u7684\u6D4B\u8BD5\u6570\u636E\u3002</p><p>\u53E6\u5916\uFF0C\u4F60\u8FD8\u8981\u8BC4\u4F30\u88AB\u6D4B\u8F6F\u4EF6\u7684\u53EF\u6D4B\u8BD5\u6027\uFF0C\u5982\u679C\u6709\u53EF\u6D4B\u8BD5\u6027\u7684\u95EE\u9898\uFF0C\u9700\u8981\u63D0\u524D\u8003\u8651\u5207\u5B9E\u53EF\u884C\u7684\u53D8\u901A\u65B9\u6848\uFF0C\u751A\u81F3\u8981\u6C42\u5F00\u53D1\u4EBA\u5458\u63D0\u4F9B\u53EF\u6D4B\u8BD5\u6027\u7684\u63A5\u53E3\u3002</p><p><strong>\u7B2C\u4E8C\uFF0C\u517C\u5BB9\u6027\u6D4B\u8BD5</strong></p><p>\u5BF9\u4E8E\u517C\u5BB9\u6027\u6D4B\u8BD5\u6765\u8BF4\uFF0CWeb \u6D4B\u8BD5\u9700\u8981\u786E\u5B9A\u8986\u76D6\u7684\u6D4F\u89C8\u5668\u7C7B\u578B\u548C\u7248\u672C\uFF0C\u79FB\u52A8\u8BBE\u5907\u6D4B\u8BD5\u9700\u8981\u786E\u5B9A\u8986\u76D6\u7684\u8BBE\u5907\u7C7B\u578B\u548C\u5177\u4F53 iOS/Android \u7684\u7248\u672C\u7B49\u3002</p><p>\u4F60\u53EF\u80FD\u4F1A\u95EE\uFF0C\u6211\u8981\u600E\u4E48\u786E\u5B9A\u9700\u8981\u8986\u76D6\u7684\u79FB\u52A8\u8BBE\u5907\u7C7B\u578B\u4EE5\u53CA iOS/Android \u7684\u7248\u672C\u5217\u8868\u5462\uFF1F\u8FD9\u4E2A\u95EE\u9898\u5176\u5B9E\u5E76\u4E0D\u96BE\uFF1A</p><ul><li>\u5982\u679C\u662F\u65E2\u6709\u4EA7\u54C1\uFF0C\u4F60\u53EF\u4EE5\u901A\u8FC7\u5927\u6570\u636E\u6280\u672F\u5206\u6790\u4EA7\u54C1\u7684\u5386\u53F2\u6570\u636E\u5F97\u51FA Top 30%\u7684\u79FB\u52A8\u8BBE\u5907\u4EE5\u53CA iOS/Android \u7684\u7248\u672C\u5217\u8868\uFF0C\u90A3\u4E48\u517C\u5BB9\u6027\u6D4B\u8BD5\u53EA\u9700\u8986\u76D6\u8FD9\u90E8\u5206\u5373\u53EF\u3002</li><li>\u5982\u679C\u662F\u4E00\u4E2A\u5168\u65B0\u7684\u4EA7\u54C1\uFF0C\u4F60\u53EF\u4EE5\u901A\u8FC7 TalkingData \u8FD9\u6837\u7684\u7F51\u7AD9\u6765\u67E5\u770B\u76EE\u524D\u4E3B\u6D41\u7684\u79FB\u52A8\u8BBE\u5907\uFF0C\u5206\u8FA8\u7387\u5927\u5C0F\u3001iOS/Android \u7248\u672C\u7B49\u4FE1\u606F\u6765\u786E\u5B9A\u6D4B\u8BD5\u8303\u56F4\u3002</li></ul><p>\u517C\u5BB9\u6027\u6D4B\u8BD5\u7684\u5B9E\u65BD\uFF0C\u5F80\u5F80\u662F\u5728\u529F\u80FD\u6D4B\u8BD5\u7684\u540E\u671F\uFF0C\u4E5F\u5C31\u662F\u8BF4\u9700\u8981\u7B49\u529F\u80FD\u57FA\u672C\u90FD\u7A33\u5B9A\u4E86\uFF0C\u624D\u4F1A\u5F00\u59CB\u517C\u5BB9\u6027\u6D4B\u8BD5\u3002</p><p>\u5F53\u7136\u4E5F\u6709\u7279\u4F8B\uFF0C\u6BD4\u5982\uFF0C\u5BF9\u4E8E\u524D\u7AEF\u5F15\u5165\u4E86\u65B0\u7684\u524D\u7AEF\u6846\u67B6\u6216\u8005\u7EC4\u4EF6\u5E93\uFF0C\u5F80\u5F80\u5C31\u4F1A\u5148\u5728\u524D\u671F\u505A\u517C\u5BB9\u6027\u8BC4\u4F30\uFF0C\u4EE5\u786E\u4FDD\u4E0D\u4F1A\u5F15\u5165\u540E\u671F\u65E0\u6CD5\u89E3\u51B3\u7684\u517C\u5BB9\u6027\u95EE\u9898\u3002</p><p>\u517C\u5BB9\u6027\u6D4B\u8BD5\u7528\u4F8B\u7684\u9009\u53D6\uFF0C\u5F80\u5F80\u6765\u81EA\u4E8E\u5DF2\u7ECF\u5B9E\u73B0\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u7528\u4F8B\u3002\u9053\u7406\u5F88\u7B80\u5355\uFF0C\u56E0\u4E3A\u517C\u5BB9\u6027\u6D4B\u8BD5\u5F80\u5F80\u8981\u8986\u76D6\u6700\u5E38\u7528\u7684\u4E1A\u52A1\u573A\u666F\uFF0C\u800C\u8FD9\u4E9B\u6700\u5E38\u7528\u7684\u4E1A\u52A1\u573A\u666F\u901A\u5E38\u4E5F\u662F\u9996\u6279\u5B9E\u73B0\u81EA\u52A8\u5316\u6D4B\u8BD5\u7684\u76EE\u6807\u3002</p><p>\u6240\u4EE5\uFF0C\u6211\u4EEC\u7684 GUI \u81EA\u52A8\u5316\u6846\u67B6\uFF0C\u5C31\u9700\u8981\u80FD\u591F\u652F\u6301\u540C\u4E00\u5957\u6D4B\u8BD5\u811A\u672C\u5728\u4E0D\u505A\u4FEE\u6539\u7684\u524D\u63D0\u4E0B\uFF0C\u8FD0\u884C\u4E8E\u4E0D\u540C\u7684\u6D4F\u89C8\u5668\u3002</p><p><strong>\u7B2C\u4E09\uFF0C\u6027\u80FD\u6D4B\u8BD5</strong></p><p>\u5BF9\u4E8E\u6027\u80FD\u6D4B\u8BD5\uFF0C\u9700\u8981\u5728\u660E\u786E\u4E86\u6027\u80FD\u9700\u6C42\uFF08\u5E76\u53D1\u7528\u6237\u6570\u3001\u54CD\u5E94\u65F6\u95F4\u3001\u4E8B\u52A1\u541E\u5410\u91CF\u7B49\uFF09\u7684\u524D\u63D0\u4E0B\uFF0C\u7ED3\u5408\u88AB\u6D4B\u7CFB\u7EDF\u7684\u7279\u70B9\uFF0C\u8BBE\u8BA1\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u5E76\u786E\u5B9A\u6027\u80FD\u6D4B\u8BD5\u6846\u67B6\u3002</p><p>\u6BD4\u5982\uFF0C\u662F\u76F4\u63A5\u5728 API \u7EA7\u522B\u53D1\u8D77\u538B\u529B\u6D4B\u8BD5\uFF0C\u8FD8\u662F\u5FC5\u987B\u6A21\u62DF\u7EC8\u7AEF\u7528\u6237\u884C\u4E3A\u8FDB\u884C\u57FA\u4E8E\u534F\u8BAE\u7684\u538B\u529B\u6D4B\u8BD5\u3002\u518D\u6BD4\u5982\uFF0C\u662F\u57FA\u4E8E\u6A21\u5757\u8FDB\u884C\u538B\u529B\u6D4B\u8BD5\uFF0C\u8FD8\u662F\u53D1\u8D77\u5168\u94FE\u8DEF\u538B\u6D4B\u3002</p><p>\u5982\u679C\u6027\u80FD\u662F\u80CC\u666F\u6570\u636E\u654F\u611F\u7684\u573A\u666F\uFF0C\u8FD8\u9700\u8981\u786E\u5B9A\u80CC\u666F\u6570\u636E\u91CF\u7EA7\u4E0E\u5206\u5E03\uFF0C\u5E76\u51B3\u5B9A\u4EA7\u751F\u80CC\u666F\u6570\u636E\u7684\u6280\u672F\u65B9\u6848\uFF0C\u6BD4\u5982\u662F\u901A\u8FC7 API \u5E76\u53D1\u8C03\u7528\u6765\u4EA7\u751F\u6D4B\u8BD5\u6570\u636E\uFF0C\u8FD8\u662F\u76F4\u63A5\u5728\u6570\u636E\u5E93\u4E0A\u505A\u6279\u91CF insert \u548C update \u64CD\u4F5C\uFF0C\u6216\u8005\u662F\u4E24\u79CD\u65B9\u5F0F\u7684\u7ED3\u5408\u3002</p><p>\u6700\u540E\uFF0C\u65E0\u8BBA\u91C7\u7528\u54EA\u79CD\u65B9\u5F0F\uFF0C\u90FD\u9700\u8981\u660E\u786E\u5F85\u5F00\u53D1\u7684\u5355\u7528\u6237\u811A\u672C\u7684\u6570\u91CF\uFF0C\u4EE5\u4FBF\u540E\u7EED\u80FD\u591F\u987A\u5229\u7EC4\u88C5\u538B\u6D4B\u6D4B\u8BD5\u573A\u666F\u3002</p><p>\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u65BD\uFF0C\u662F\u4E00\u4E2A\u6BD4\u8F83\u590D\u6742\u7684\u95EE\u9898\u3002\u9996\u5148\uFF0C\u9700\u8981\u6839\u636E\u4F60\u60F3\u8981\u89E3\u51B3\u7684\u95EE\u9898\uFF0C\u786E\u5B9A\u6027\u80FD\u6D4B\u8BD5\u7684\u7C7B\u578B\uFF1B\u7136\u540E\uFF0C\u6839\u636E\u5177\u4F53\u7684\u6027\u80FD\u6D4B\u8BD5\u7C7B\u578B\u5F00\u5C55\u6D4B\u8BD5\u3002</p><ol><li><p>\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u65BD\uFF0C\u5F80\u5F80\u5148\u8981\u6839\u636E\u4E1A\u52A1\u573A\u666F\u6765\u51B3\u5B9A\u9700\u8981\u5F00\u53D1\u54EA\u4E9B\u5355\u7528\u6237\u811A\u672C\uFF0C\u811A\u672C\u7684\u5F00\u53D1\u4F1A\u6D89\u53CA\u5230\u5F88\u591A\u6027\u80FD\u6D4B\u8BD5\u811A\u672C\u7279\u6709\u7684\u6982\u5FF5\uFF0C\u6BD4\u5982\u601D\u8003\u65F6\u95F4\u3001\u96C6\u5408\u70B9\u3001\u52A8\u6001\u5173\u8054\u7B49\u7B49\u3002</p></li><li><p>\u811A\u672C\u5F00\u53D1\u5B8C\u6210\u540E\uFF0C\u4F60\u8FD8\u8981\u4EE5\u811A\u672C\u4E3A\u5355\u4F4D\u7EC4\u7EC7\u6D4B\u8BD5\u573A\u666F\uFF08Scenario\uFF09\uFF0C\u573A\u666F\u5B9A\u4E49\u7B80\u5355\u6765\u8BF4\u5C31\u662F\u767E\u5206\u4E4B\u591A\u5C11\u7684\u7528\u6237\u5728\u505A\u767B\u5F55\u3001\u767E\u5206\u4E4B\u591A\u5C11\u7684\u7528\u6237\u5728\u505A\u67E5\u8BE2\u3001\u6BCF\u4E2A\u7528\u6237\u7684\u64CD\u4F5C\u6B65\u9AA4\u4E4B\u95F4\u9700\u8981\u7B49\u5F85\u591A\u5C11\u65F6\u95F4\u3001\u5E76\u53D1\u7528\u6237\u7684\u589E\u901F\u662F 5 \u79D2\u4E00\u4E2A\uFF0C\u8FD8\u662F 5 \u79D2 2 \u4E2A\u7B49\u7B49\u3002</p></li><li><p>\u6700\u540E\uFF0C\u624D\u662F\u5177\u4F53\u7684\u6D4B\u8BD5\u573A\u666F\u6267\u884C\u3002\u548C\u81EA\u52A8\u5316\u529F\u80FD\u6D4B\u8BD5\u4E0D\u540C\uFF0C\u6027\u80FD\u6D4B\u8BD5\u6267\u884C\u5B8C\u6210\u540E\u6027\u80FD\u6D4B\u8BD5\u62A5\u544A\u7684\u89E3\u8BFB\uFF0C\u662F\u6574\u4E2A\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\u6700\u5173\u952E\u7684\u70B9\u3002</p></li></ol><p>\u5982\u679C\u4F60\u73B0\u5728\u4E0D\u592A\u6E05\u695A\u6211\u4E0A\u9762\u63D0\u5230\u7684\u4E00\u4E9B\u6982\u5FF5\u4E5F\u6CA1\u5173\u7CFB\uFF0C\u6211\u4F1A\u5728\u540E\u7EED\u7684\u6587\u7AE0\u4E2D\u4E3A\u4F60\u8BE6\u7EC6\u8BB2\u89E3\u3002</p><p>\u9664\u4E86\u6211\u7ED9\u4F60\u8BE6\u7EC6\u5206\u6790\u7684\u3001\u6700\u5E38\u7528\u7684\u529F\u80FD\u6D4B\u8BD5\u3001\u517C\u5BB9\u6027\u6D4B\u8BD5\u548C\u6027\u80FD\u6D4B\u8BD5\u5916\uFF0C\u8FD8\u6709\u5F88\u591A\u6D4B\u8BD5\u7C7B\u578B\uFF08\u6BD4\u5982\uFF0C\u63A5\u53E3\u6D4B\u8BD5\u3001\u96C6\u6210\u6D4B\u8BD5\u3001\u5B89\u5168\u6D4B\u8BD5\u3001\u5BB9\u91CF\u9A8C\u8BC1\u3001\u5B89\u88C5\u6D4B\u8BD5\u3001\u6545\u969C\u6062\u590D\u6D4B\u8BD5\u7B49\uFF09\u3002\u8FD9\u4E9B\u6D4B\u8BD5\u7C7B\u578B\uFF0C\u90FD\u6709\u5404\u81EA\u7684\u5E94\u7528\u573A\u666F\uFF0C\u4E5F\u76F8\u5E94\u6709\u72EC\u7279\u7684\u6D4B\u8BD5\u65B9\u6CD5\uFF0C\u5728\u8FD9\u91CC\u6211\u5C31\u4E0D\u518D\u4E00\u4E00\u5C55\u5F00\u4E86\uFF0C\u5982\u679C\u4F60\u6709\u5173\u4E8E\u8FD9\u4E9B\u6D4B\u8BD5\u7C7B\u578B\u7684\u95EE\u9898\uFF0C\u53EF\u4EE5\u7ED9\u6211\u7559\u8A00\u8BA8\u8BBA\u3002</p><p><strong>\u6D4B\u8BD5\u8D44\u6E90</strong></p><p>\u6D4B\u8BD5\u8D44\u6E90\u901A\u5E38\u5305\u62EC\u6D4B\u8BD5\u4EBA\u5458\u548C\u6D4B\u8BD5\u73AF\u5883\uFF0C\u8FD9\u4E24\u7C7B\u8D44\u6E90\u90FD\u662F\u6709\u9650\u7684\u3002\u6D4B\u8BD5\u8BA1\u5212\u7684\u76EE\u7684\u5C31\u662F\uFF0C\u4FDD\u8BC1\u5728\u6709\u9650\u8D44\u6E90\u4E0B\u7684\u4EA7\u51FA\u6700\u5927\u5316\u3002\u6240\u4EE5\uFF0C<strong>\u6D4B\u8BD5\u8D44\u6E90\u5C31\u662F\u9700\u8981\u660E\u786E\u201C\u8C01\u6765\u6D4B\u201D\u548C\u201C\u5728\u54EA\u91CC\u6D4B\u201D\u8FD9\u4E24\u4E2A\u95EE\u9898</strong>\u3002</p><p>\u6D4B\u8BD5\u4EBA\u5458\u662F\u6700\u91CD\u8981\u7684\uFF0C\u76F4\u63A5\u5173\u7CFB\u5230\u6574\u4E2A\u6D4B\u8BD5\u9879\u76EE\u7684\u6210\u8D25\u548C\u6548\u7387\u3002\u6D4B\u8BD5\u4EBA\u5458\u7684\u8D44\u6E90\u901A\u5E38\u6709\u4E24\u4E2A\u7EF4\u5EA6\uFF1A\u4E00\u662F\uFF0C\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u7684\u6570\u91CF\uFF1B\u4E8C\u662F\uFF0C\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u7684\u4E2A\u4EBA\u7ECF\u9A8C\u548C\u80FD\u529B\u3002</p><p>\u4F60\u4F1A\u53D1\u73B0\uFF0C\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u7684\u7ECF\u9A8C\u548C\u80FD\u529B\u4E0D\u8DB3\uFF0C\u5F88\u96BE\u901A\u8FC7\u6D4B\u8BD5\u4EBA\u5458\u7684\u6570\u91CF\u6765\u5F25\u8865\u3002\u76F8\u53CD\u5730\uFF0C\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u7684\u7ECF\u9A8C\u548C\u80FD\u529B\u90FD\u975E\u5E38\u5F3A\u7684\u60C5\u51B5\u4E0B\uFF0C\u6D4B\u8BD5\u4EBA\u5458\u7684\u6570\u91CF\u53EF\u4EE5\u9002\u5F53\u5730\u51CF\u5C11\u3002</p><p>\u901A\u5E38\u5728\u6D4B\u8BD5\u56E2\u961F\u4E2D\uFF0C\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u65E2\u6709\u8D44\u6DF1\uFF0C\u4E5F\u4F1A\u6709\u521D\u7EA7\uFF0C\u90A3\u4E48\u4F60\u5C31\u5FC5\u987B\u9488\u5BF9\u56E2\u961F\u7684\u5B9E\u9645\u60C5\u51B5\u53BB\u5B89\u6392\u6D4B\u8BD5\u8BA1\u5212\u3002\u6BD4\u5982\uFF0C\u96BE\u5EA6\u8F83\u5927\u7684\u5DE5\u4F5C\uFF0C\u6216\u8005\u4E00\u4E9B\u65B0\u5DE5\u5177\u3001\u65B0\u65B9\u6CD5\u7684\u5E94\u7528\uFF0C\u53C8\u6216\u8005\u81EA\u52A8\u5316\u6D4B\u8BD5\u5F00\u53D1\u5DE5\u4F5C\uFF0C\u901A\u5E38\u7531\u8D44\u6DF1\u7684\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u6765\u627F\u62C5\uFF1B\u800C\u90A3\u4E9B\u76F8\u5BF9\u673A\u68B0\u6027\u3001\u96BE\u5EA6\u8F83\u5C0F\u7684\u5DE5\u4F5C\uFF0C\u5219\u7531\u521D\u7EA7\u5DE5\u7A0B\u5E08\u5B8C\u6210\u3002</p><p>\u53EF\u89C1\uFF0C\u4F60\u8981\u60F3\u89C4\u5212\u597D\u6D4B\u8BD5\u8D44\u6E90\uFF0C\u9664\u4E86\u8981\u4E86\u89E3\u9879\u76EE\u672C\u8EAB\u5916\uFF0C\u8FD8\u5FC5\u987B\u5BF9\u6D4B\u8BD5\u56E2\u961F\u7684\u4EBA\u5458\u7279\u70B9\u6709\u6E05\u6670\u7684\u628A\u63A7\u3002\u53E6\u5916\uFF0C\u6211\u5F3A\u70C8\u5EFA\u8BAE\u4F60\u628A\u5177\u4F53\u7684\u4EFB\u52A1\u6E05\u6670\u5730\u843D\u5B9E\u5230\u6BCF\u4E2A\u4EBA\u7684\u8EAB\u4E0A\uFF0C\u8FD9\u5C06\u6709\u5229\u4E8E\u5EFA\u7ACB\u6E05\u6670\u7684\u8D23\u4EFB\u673A\u5236\uFF0C\u907F\u514D\u540E\u7EED\u53EF\u80FD\u53D1\u751F\u7684\u626F\u76AE\u3002</p><p>\u76F8\u5BF9\u4E8E\u6D4B\u8BD5\u4EBA\u5458\uFF0C\u6D4B\u8BD5\u73AF\u5883\u5C31\u6BD4\u8F83\u597D\u7406\u89E3\u4E86\u3002\u4E0D\u540C\u7684\u9879\u76EE\uFF0C\u53EF\u80FD\u4F1A\u4F7F\u7528\u5171\u4EAB\u7684\u6D4B\u8BD5\u73AF\u5883\uFF0C\u4E5F\u53EF\u80FD\u4F7F\u7528\u4E13\u7528\u7684\u6D4B\u8BD5\u73AF\u5883\uFF0C\u751A\u81F3\u8FD8\u4F1A\u76F4\u63A5\u4F7F\u7528\u751F\u4EA7\u73AF\u5883\u3002\u53E6\u5916\uFF0C\u5BF9\u4E8E\u76EE\u524D\u4E00\u4E9B\u5DF2\u7ECF\u5B9E\u73B0\u5BB9\u5668\u5316\u90E8\u7F72\u4E0E\u53D1\u5E03\u7684\u9879\u76EE\uFF0C\u6D4B\u8BD5\u73AF\u5883\u5C31\u4F1A\u53D8\u5F97\u66F4\u7B80\u5355\u4E0E\u8F7B\u91CF\u7EA7\uFF0C\u8FD9\u90E8\u5206\u5185\u5BB9\u6211\u4F1A\u5728\u540E\u7EED\u7684\u6587\u7AE0\u4E2D\u7ED9\u4F60\u8BE6\u7EC6\u8BB2\u89E3\u3002</p><p><strong>\u6D4B\u8BD5\u8FDB\u5EA6</strong></p><p>\u5728\u660E\u786E\u4E86\u6D4B\u8BD5\u8303\u56F4\u3001\u6D4B\u8BD5\u7B56\u7565\u548C\u6D4B\u8BD5\u8D44\u6E90\u4E4B\u540E\uFF0C\u4F60\u5C31\u8981\u8003\u8651\u5177\u4F53\u7684\u6D4B\u8BD5\u8FDB\u5EA6\u4E86\u3002<strong>\u6D4B\u8BD5\u8FDB\u5EA6\u4E3B\u8981\u63CF\u8FF0\u5404\u7C7B\u6D4B\u8BD5\u7684\u5F00\u59CB\u65F6\u95F4\uFF0C\u6240\u9700\u5DE5\u4F5C\u91CF\uFF0C\u9884\u8BA1\u5B8C\u6210\u65F6\u95F4\uFF0C\u5E76\u4EE5\u6B64\u4E3A\u4F9D\u636E\u6765\u5EFA\u8BAE\u6700\u7EC8\u4EA7\u54C1\u7684\u4E0A\u7EBF\u53D1\u5E03\u65F6\u95F4</strong>\u3002</p><p>\u6BD4\u5982\uFF0C\u7248\u672C\u63A5\u53D7\u6D4B\u8BD5\uFF08Build Acceptance Test\uFF09\u7684\u5DE5\u4F5C\u91CF\uFF0C\u5192\u70DF\u6D4B\u8BD5\uFF08Smoke Test\uFF09\u7684\u5DE5\u4F5C\u91CF\uFF0C\u81EA\u52A8\u5316\u811A\u672C\u5F00\u53D1\u7684\u5DE5\u4F5C\u91CF\uFF0C\u7F3A\u9677\u4FEE\u590D\u7684\u9A8C\u8BC1\u5DE5\u4F5C\u91CF\uFF0C\u9700\u8981\u51E0\u8F6E\u56DE\u5F52\u6D4B\u8BD5\u3001\u6BCF\u4E00\u8F6E\u56DE\u5F52\u6D4B\u8BD5\u7684\u5DE5\u4F5C\u91CF\u7B49\u7B49\u3002</p><p>\u5728\u4F20\u7EDF\u7011\u5E03\u6A21\u578B\u4E2D\uFF0C\u6D4B\u8BD5\u8FDB\u5EA6\u5B8C\u5168\u4F9D\u8D56\u4E8E\u5F00\u53D1\u5B8C\u6210\u5E76\u9012\u4EA4\u6D4B\u8BD5\u7248\u672C\u7684\u65F6\u95F4\u3002\u5982\u679C\u5F00\u53D1\u63D0\u4EA4\u6D4B\u8BD5\u7248\u672C\u53D1\u751F\u4E86\u5EF6\u8BEF\uFF0C\u90A3\u4E48\u5728\u4E0D\u88C1\u526A\u6D4B\u8BD5\u9700\u6C42\u7684\u60C5\u51B5\u4E0B\uFF0C\u4EA7\u54C1\u6574\u4F53\u7684\u4E0A\u7EBF\u65F6\u95F4\u5C31\u540C\u6837\u4F1A\u5EF6\u671F\u3002</p><p>\u7136\u800C\u5728\u654F\u6377\u6A21\u5F0F\u4E0B\uFF0C\u6D4B\u8BD5\u6D3B\u52A8\u8D2F\u7A7F\u4E8E\u6574\u4E2A\u5F00\u53D1\u8FC7\u7A0B\uFF0C\u5F88\u591A\u6D4B\u8BD5\u5DE5\u4F5C\u4F1A\u548C\u5F00\u53D1\u5DE5\u4F5C\u540C\u6B65\u8FDB\u884C\uFF0C\u6BD4\u5982\u91C7\u7528\u884C\u4E3A\u9A71\u52A8\u5F00\u53D1\uFF08Behavior-Driven Development\uFF09\u6A21\u5F0F\uFF0C\u8FD9\u6837\u6D4B\u8BD5\u8FDB\u5EA6\u5C31\u4E0D\u4F1A\u5B8C\u5168\u4F9D\u8D56\u4E8E\u5F00\u53D1\u9012\u4EA4\u53EF\u6D4B\u8BD5\u7248\u672C\u7684\u65F6\u95F4\u3002</p><p>\u884C\u4E3A\u9A71\u52A8\u5F00\u53D1\uFF0C\u5C31\u662F\u5E73\u65F6\u6211\u4EEC\u7ECF\u5E38\u8BF4\u7684 BDD\uFF0C\u6307\u7684\u662F\u53EF\u4EE5\u901A\u8FC7\u81EA\u7136\u8BED\u8A00\u4E66\u5199\u975E\u7A0B\u5E8F\u5458\u53EF\u8BFB\u7684\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u5E76\u901A\u8FC7 StepDef \u6765\u5173\u8054\u57FA\u4E8E\u81EA\u7136\u8BED\u8A00\u7684\u6B65\u9AA4\u63CF\u8FF0\u548C\u5177\u4F53\u7684\u4E1A\u52A1\u64CD\u4F5C\uFF0C\u6700\u5178\u578B\u7684\u6846\u67B6\u5C31\u662F\u77E5\u540D\u201CCucumber\u201D\u3002</p><p><strong>\u6D4B\u8BD5\u98CE\u9669\u9884\u4F30</strong></p><p>\u4FD7\u8BDD\u8BF4\uFF0C\u8BA1\u5212\u8D76\u4E0D\u4E0A\u53D8\u5316\uFF0C\u5BF9\u4E8E\u6D4B\u8BD5\u4E5F\u662F\u4E00\u6837\u7684\u9053\u7406\uFF0C\u5F88\u5C11\u6709\u6574\u4E2A\u6D4B\u8BD5\u8FC7\u7A0B\u662F\u5B8C\u5168\u6309\u7167\u539F\u672C\u6D4B\u8BD5\u8BA1\u5212\u6267\u884C\u7684\u3002\u901A\u5E38\u9700\u6C42\u53D8\u66F4\u3001\u5F00\u53D1\u5EF6\u671F\u3001\u53D1\u73B0\u91CD\u5927\u7F3A\u9677\u548C\u4EBA\u5458\u53D8\u52A8\u662F\u5F15\u5165\u9879\u76EE\u6D4B\u8BD5\u98CE\u9669\u7684\u4E3B\u8981\u539F\u56E0\u3002</p><p>\u5BF9\u4E8E\u9700\u6C42\u53D8\u66F4\uFF0C\u6BD4\u5982\u589E\u52A0\u9700\u6C42\u3001\u5220\u51CF\u9700\u6C42\u3001\u4FEE\u6539\u9700\u6C42\u7B49\uFF0C\u4E00\u5B9A\u8981\u91CD\u65B0\u8FDB\u884C\u6D4B\u8BD5\u9700\u6C42\u5206\u6790\uFF0C\u786E\u5B9A\u53D8\u66F4\u540E\u7684\u6D4B\u8BD5\u8303\u56F4\u548C\u8D44\u6E90\u8BC4\u4F30\uFF0C\u5E76\u4E0E\u9879\u76EE\u7ECF\u7406\u548C\u4EA7\u54C1\u7ECF\u7406\u53CA\u65F6\u6C9F\u901A\u56E0\u6B64\u5F15\u8D77\u7684\u6D4B\u8BD5\u8FDB\u5EA6\u53D8\u5316\u3002\u6D4B\u8BD5\u7ECF\u7406/\u6D4B\u8BD5\u8D1F\u8D23\u4EBA\u5207\u5FCC\u4E0D\u80FD\u6709\u81EA\u5DF1\u54AC\u7259\u625B\u8FC7\u53BB\u7684\u60F3\u6CD5\uFF0C\u5426\u5219\u65E0\u8BBA\u662F\u5BF9\u6D4B\u8BD5\u56E2\u961F\u8FD8\u662F\u5BF9\u4EA7\u54C1\u672C\u8EAB\u90FD\u4E0D\u4F1A\u6709\u4EFB\u4F55\u597D\u5904\u3002</p><p>\u53E6\u5916\uFF0C\u968F\u7740\u6D4B\u8BD5\u7684\u5F00\u5C55\uFF0C\u4F60\u53EF\u80FD\u4F1A\u53D1\u73B0\u524D\u671F\u5BF9\u4E8E\u6D4B\u8BD5\u5DE5\u4F5C\u91CF\u7684\u9884\u4F30\u4E0D\u591F\u51C6\u786E\uFF0C\u4E5F\u53EF\u80FD\u53D1\u73B0\u9700\u8981\u589E\u52A0\u66F4\u591A\u7684\u6D4B\u8BD5\u7C7B\u578B\uFF0C\u4E5F\u53EF\u80FD\u53D1\u73B0\u56E0\u4E3A\u8981\u4FEE\u6539\u6D4B\u8BD5\u67B6\u6784\u7684\u4E25\u91CD\u7F3A\u9677\u800C\u5BFC\u81F4\u5F88\u591A\u7684\u6D4B\u8BD5\u9700\u8981\u5168\u56DE\u5F52\uFF0C\u8FD8\u6709\u53EF\u80FD\u51FA\u73B0\u5F00\u53D1\u9012\u4EA4\u6D4B\u8BD5\u7248\u672C\u5EF6\u671F\uFF0C\u6216\u8005\u4EBA\u5458\u53D8\u52A8\u7B49\u5404\u79CD\u60C5\u51B5\u3002</p><p>\u6240\u4EE5\uFF0C<strong>\u5728\u5236\u5B9A\u6D4B\u8BD5\u8BA1\u5212\u65F6\uFF0C\u4F60\u5C31\u8981\u9884\u4F30\u6574\u4E2A\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\u53EF\u80FD\u5B58\u5728\u7684\u6F5C\u5728\u98CE\u9669\uFF0C\u4EE5\u53CA\u5F53\u8FD9\u4E9B\u98CE\u9669\u53D1\u751F\u65F6\u7684\u5E94\u5BF9\u7B56\u7565</strong>\u3002 \u90A3\u4E48\uFF0C\u5728\u771F\u7684\u9047\u5230\u7C7B\u4F3C\u95EE\u9898\u65F6\uFF0C\u4F60\u624D\u53EF\u4EE5\u505A\u5230\u5FC3\u4E2D\u4E0D\u614C\uFF0C\u6709\u6761\u4E0D\u7D0A\u5730\u5E94\u5BF9\u8FD9\u4E9B\u6311\u6218\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u8F6F\u4EF6\u6D4B\u8BD5\u540C\u8F6F\u4EF6\u9879\u76EE\u4E00\u6837\uFF0C\u4E5F\u8981\u5236\u5B9A\u8BE6\u7EC6\u7684\u6D4B\u8BD5\u8BA1\u5212\u3002\u867D\u7136\u5728\u654F\u6377\u5F00\u53D1\u6A21\u5F0F\u4E0B\uFF0C\u8F6F\u4EF6\u6D4B\u8BD5\u4E0D\u518D\u5C40\u9650\u4E8E\u539A\u91CD\u7684\u3001\u6B63\u5F0F\u7684\u8BA1\u5212\u6587\u6863\uFF0C\u4F46\u662F\u6D4B\u8BD5\u8BA1\u5212\u7684\u91CD\u8981\u6027\u4E1D\u6BEB\u6CA1\u6709\u53D1\u751F\u53D8\u5316\u3002</p><p>\u4E00\u4EFD\u6210\u529F\u7684\u6D4B\u8BD5\u8BA1\u5212\uFF0C\u5FC5\u987B\u6E05\u695A\u5730\u63CF\u8FF0\uFF1A\u6D4B\u8BD5\u8303\u56F4\u3001\u6D4B\u8BD5\u7B56\u7565\u3001\u6D4B\u8BD5\u8D44\u6E90\u3001\u6D4B\u8BD5\u8FDB\u5EA6\u548C\u6D4B\u8BD5\u98CE\u9669\u9884\u4F30\u8FD9\u4E94\u4E2A\u6700\u91CD\u8981\u7684\u65B9\u9762\u3002</p><p>\u6D4B\u8BD5\u8303\u56F4\u9700\u8981\u660E\u786E\u201C\u6D4B\u4EC0\u4E48\u201D\u548C\u201C\u4E0D\u6D4B\u4EC0\u4E48\u201D\uFF1B\u6D4B\u8BD5\u7B56\u7565\u9700\u8981\u660E\u786E\u201C\u5148\u6D4B\u4EC0\u4E48\u540E\u6D4B\u4EC0\u4E48\u201D\u548C\u201C\u5982\u4F55\u6765\u6D4B\u201D\uFF1B\u6D4B\u8BD5\u8D44\u6E90\u9700\u8981\u660E\u786E\u201C\u8C01\u6765\u6D4B\u201D\u548C\u201C\u5728\u54EA\u91CC\u6D4B\u201D\uFF1B\u6D4B\u8BD5\u8FDB\u5EA6\u662F\u9700\u8981\u660E\u786E\u5404\u7C7B\u6D4B\u8BD5\u7684\u5F00\u59CB\u65F6\u95F4\uFF0C\u6240\u9700\u5DE5\u4F5C\u91CF\u548C\u9884\u8BA1\u5B8C\u6210\u65F6\u95F4\uFF1B\u6D4B\u8BD5\u98CE\u9669\u9884\u4F30\u662F\u9700\u8981\u660E\u786E\u5982\u4F55\u6709\u6548\u5E94\u5BF9\u5404\u79CD\u6F5C\u5728\u7684\u53D8\u5316\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u5728\u8FD9\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u53EA\u548C\u4F60\u5206\u4EAB\u4E86\u505A\u597D\u6D4B\u8BD5\u8BA1\u5212\u4E2D\u6700\u6700\u5173\u952E\u7684\u5185\u5BB9\uFF0C\u610F\u5728\u629B\u7816\u5F15\u7389\u3002\u90A3\u4E48\uFF0C\u4F60\u5728\u5DE5\u7A0B\u5B9E\u8DF5\u4E2D\uFF0C\u8FD8\u6709\u54EA\u4E9B\u89C1\u89E3\u5462\uFF1F</p>',74);function o(s,g){return n}var i=p(t,[["render",o],["__file","08.html.vue"]]);export{i as default};
